async function setDouyinCompositeCover(client, content) {
  const actions = [];
  const coverSlots = resolveExpectedCoverSlotsForPlatform("douyin", content).filter((item) => String(item.cover_path || "").trim());
  const fallbackCoverPath = expectedCoverPath(content);
  const uploadPlan = coverSlots.length
    ? coverSlots
    : (fallbackCoverPath ? [{ slot: "primary", label: "设置封面", matrix_key: "", target_size: null, cover_path: fallbackCoverPath }] : []);
  if (!uploadPlan.length) return actions;
  const editorPlan = buildDouyinCompositeCoverEditorPlan(uploadPlan);
  actions.push({
    kind: "douyin_cover_editor_plan",
    plan: editorPlan.map((item) => ({ slot: item.slot, label: item.label, cover_path: item.cover_path })),
  });
  const before = await readDouyinCoverSurface(client).catch(() => ({}));
  actions.push({
    kind: "douyin_cover_surface_before",
    ...before,
  });

  const preExistingEditor = await inspectDouyinCoverEditorState(client).catch(() => ({}));
  let editorReady = isDouyinFormalCompositeCoverEditorState(preExistingEditor);
  if (!editorReady && preExistingEditor?.editor_open) {
    const dismissActions = await dismissInterruptions(client, null, "douyin", "douyin_cover_unexpected_preexisting_editor_branch").catch(() => []);
    actions.push({
      kind: "douyin_cover_unexpected_editor_branch_before_entry",
      blocked: true,
      reason: "non_formal_cover_editor_rejected",
      root_text: String(preExistingEditor?.root_text || "").slice(0, 400),
      dismiss_actions: Array.isArray(dismissActions) ? dismissActions : [],
    });
    await sleep(900);
  }

  if (!editorReady) {
    const initialSlot = editorPlan[0];
    const entry = await clickDouyinCoverSlotEditor(client, [initialSlot.label, initialSlot.slot]).catch(() => ({ clicked: false }));
    actions.push({ kind: "douyin_cover_entry", slot: initialSlot.slot, slot_label: initialSlot.label, ...entry });
    if (!entry?.clicked) {
      actions.push({
        kind: "douyin_cover_entry_missing",
        slot: initialSlot.slot,
        slot_label: initialSlot.label,
        clicked: false,
        reason: "cover_slot_entry_not_found",
      });
      return actions;
    }
    await sleep(1200);
  }

  const openedEditor = await inspectDouyinCoverEditorState(client).catch(() => ({}));
  const formalOpenedEditor = isDouyinFormalCompositeCoverEditorState(openedEditor);
  actions.push({
    kind: "douyin_cover_editor_open_state",
    formal_editor_state: formalOpenedEditor,
    immediate_editable: isDouyinCoverEditorImmediateEditable(openedEditor),
    ...openedEditor,
  });
  if (!formalOpenedEditor) {
    actions.push({
      kind: "douyin_cover_entry_missing",
      clicked: false,
      reason: "formal_douyin_cover_editor_not_open",
      root_text: String(openedEditor?.root_text || "").slice(0, 400),
    });
    return actions;
  }

  let uploadedCount = 0;
  for (let index = 0; index < editorPlan.length; index += 1) {
    const slot = editorPlan[index];
    if (index > 0) {
      const switchAction = await clickDouyinCoverEditorSwitch(client, slot.slot).catch(() => ({ clicked: false, reason: "douyin_cover_editor_switch_error" }));
      actions.push({ kind: "douyin_cover_editor_switch", slot: slot.slot, slot_label: slot.label, ...switchAction });
      if (!switchAction?.clicked) continue;
      await sleep(900);
    }
    const upload = await setImageFileInputByAccept(client, slot.cover_path, {
      preferDialog: true,
      preferVisible: false,
      contextTexts: [slot.label, slot.slot, "上传封面", "设置横封面", "设置竖封面", "封面检测"],
      preferRootTexts: [slot.label, "上传封面", "设置横封面", "设置竖封面", "横封面预览", "竖封面预览"],
      avoidRootTexts: ["生成参考图", "智能参考", "AI生成封面", "参考图", "为你推荐"],
    });
    actions.push({ kind: "douyin_cover_upload", slot: slot.slot, slot_label: slot.label, expected_path: slot.cover_path, ...upload });
    await sleep(500);
    const immediateEditorState = await inspectDouyinCoverEditorState(client).catch(() => ({}));
    const formalEditorState = isDouyinFormalCompositeCoverEditorState(immediateEditorState);
    const immediateEditable = isDouyinCoverEditorImmediateEditable(immediateEditorState);
    actions.push({
      kind: "douyin_cover_editor_state_after_upload",
      slot: slot.slot,
      slot_label: slot.label,
      formal_editor_state: formalEditorState,
      immediate_editable: immediateEditable,
      ...immediateEditorState,
    });
    if (immediateEditorState?.editor_open && !formalEditorState) {
      const dismissActions = await dismissInterruptions(client, null, "douyin", "douyin_cover_unexpected_editor_branch").catch(() => []);
      actions.push({
        kind: "douyin_cover_unexpected_editor_branch",
        slot: slot.slot,
        slot_label: slot.label,
        blocked: true,
        reason: "non_formal_cover_editor_rejected",
        root_text: String(immediateEditorState?.root_text || "").slice(0, 400),
        dismiss_actions: Array.isArray(dismissActions) ? dismissActions : [],
      });
      continue;
    }
    const uploadReady = await waitForDouyinCoverEditorUploadReady(client, { timeoutMs: 14000 }).catch(() => ({ ready: false }));
    actions.push({ kind: "douyin_cover_upload_ready", slot: slot.slot, slot_label: slot.label, ...uploadReady });
    if (!uploadReady?.ready) continue;
    uploadedCount += 1;
  }

  actions.push({
    kind: "douyin_cover_editor_upload_progress",
    uploaded_count: uploadedCount,
    required_count: editorPlan.length,
    ready_for_confirm: uploadedCount === editorPlan.length,
  });
  if (uploadedCount === editorPlan.length) {
    const confirm = await clickDouyinCoverConfirm(client);
    actions.push({ kind: "douyin_cover_confirm", ...confirm });
    const closed = await waitForDouyinCoverEditorClose(client, { timeoutMs: 12000 }).catch(() => ({ closed: false }));
    actions.push({ kind: "douyin_cover_editor_close", ...closed });
    await sleep(closed?.closed ? 900 : 1600);
  }
  const after = await readDouyinCoverSurface(client).catch(() => ({}));
  const coverState = deriveDouyinCoverState({
    textHaystack: [after.body_text, ...(after.lines || [])].filter(Boolean).join(" "),
    expectedCoverPath: fallbackCoverPath || String(uploadPlan[0]?.cover_path || ""),
    expectedCoverSlots: uploadPlan.map((item) => ({
      slot: item.slot,
      label: item.label,
      cover_path: item.cover_path,
      matrix_key: item.matrix_key,
    })),
    coverActual: after.cover_actual,
    imageSources: after.image_sources,
    backgroundSources: after.background_sources,
    slotSurfaces: after.slot_surfaces,
    modalOpen: Boolean(after.modal_open),
  });
  actions.push({
    kind: "douyin_cover_surface_after",
    ready: coverState.custom_cover_ready,
    saved: coverState.saved,
    expected_slots: uploadPlan.map((item) => ({ slot: item.slot, label: item.label, expected_path: item.cover_path })),
    slot_states: coverState.slots,
    cover_state: coverState,
    ...after,
  });
  return actions;
}

async function selectCompositeCollection(client, platform, content) {
  const collection = expectedCollectionNameForPlatform(platform, content);
  if (!collection) return [];
  if (platform === "kuaishou") {
    return await selectKuaishouCollection(client, collection);
  }
  if (platform === "youtube") {
    return await selectYouTubePlaylist(client, collection);
  }
  const actions = [];
  const entryTexts = platform === "youtube"
    ? ["播放列表", "Playlist", "选择"]
    : ["加入合集", "选择合集", "合集", "播放列表", "选择", "创建合集"];
  actions.push({ kind: `${platform}_collection_entry`, ...(await clickByText(client, entryTexts)) });
  await sleep(1000);
  actions.push({ kind: `${platform}_collection_select`, ...(await clickByText(client, [collection])) });
  if (!actions.at(-1)?.clicked) actions.push({ kind: `${platform}_collection_select_loose`, ...(await clickLooseText(client, [collection])) });
  await sleep(800);
  return actions;
}

function actionTextIndicatesYouTubePlaylistSelected(actions = [], playlistName = "") {
  const target = String(playlistName || "").replace(/\s+/g, " ").trim();
  if (!target) return false;
  const chunks = [];
  const visit = (value, depth = 0) => {
    if (value == null || depth > 4) return;
    if (typeof value === "string" || typeof value === "number" || typeof value === "boolean") {
      chunks.push(String(value));
      return;
    }
    if (Array.isArray(value)) {
      for (const item of value.slice(0, 80)) visit(item, depth + 1);
      return;
    }
    if (typeof value === "object") {
      for (const key of [
        "text",
        "row_text",
        "actual",
        "actual_body",
        "body",
        "message",
        "reason",
        "visible_lines",
        "relevant_lines",
        "lines",
        "overlays",
        "headings",
        "last",
      ]) {
        if (Object.prototype.hasOwnProperty.call(value, key)) visit(value[key], depth + 1);
      }
    }
  };
  for (const action of actions.slice(-24)) visit(action);
  const text = chunks.join(" ").replace(/\s+/g, " ").trim();
  return text.includes(target) && /播放列表|playlist/i.test(text);
}

async function selectYouTubePlaylist(client, playlistName) {
  const actions = [];
  const target = String(playlistName || "").trim();
  if (!target) return actions;
  const entry = await evaluateWithClient(client, `(() => {
    const visible = (el) => {
      if (!el || typeof el.getBoundingClientRect !== "function") return false;
      const rect = el.getBoundingClientRect();
      const style = getComputedStyle(el);
      return rect.width > 0
        && rect.height > 0
        && rect.bottom > 0
        && rect.right > 0
        && rect.top < window.innerHeight
        && rect.left < window.innerWidth
        && style.display !== "none"
        && style.visibility !== "hidden"
        && !el.disabled
        && el.getAttribute("aria-disabled") !== "true";
    };
    const row = document.querySelector("ytcp-video-metadata-playlists");
    if (!row) return { clicked: false, reason: "playlist_row_missing" };
    row.scrollIntoView({ block: "center", inline: "center" });
    const candidate = [
      row.querySelector("ytcp-dropdown-trigger[aria-label],ytcp-dropdown-trigger"),
      row.querySelector("[role=button][aria-label],button,[role=button],ytcp-text-dropdown-trigger"),
      row,
    ].find((el) => el && visible(el));
    if (!candidate) return { clicked: false, reason: "playlist_control_missing" };
    const rect = candidate.getBoundingClientRect();
    return {
      clicked: false,
      needs_native_click: true,
      x: rect.left + rect.width / 2,
      y: rect.top + rect.height / 2,
      width: rect.width,
      height: rect.height,
      label: String(candidate.getAttribute("aria-label") || candidate.tagName || "").slice(0, 160),
    };
  })()`, 4000);
  if (entry?.needs_native_click && Number.isFinite(Number(entry.x)) && Number.isFinite(Number(entry.y))) {
    await dispatchMouseClick(client, Number(entry.x), Number(entry.y));
    entry.clicked = true;
    entry.click_mode = "native_cdp_coordinate";
  }
  actions.push({ kind: "youtube_collection_entry", ...entry });
  await sleep(900);
  let selection = await evaluateWithClient(client, `(async () => {
    const target = ${JSON.stringify(target)};
    const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
    const clean = (value) => String(value || "").replace(/\\s+/g, " ").trim();
    const visible = (el) => {
      if (!el || typeof el.getBoundingClientRect !== "function") return false;
      const rect = el.getBoundingClientRect();
      const style = getComputedStyle(el);
      return rect.width > 0 && rect.height > 0 && style.display !== "none" && style.visibility !== "hidden" && !el.disabled && el.getAttribute("aria-disabled") !== "true";
    };
    const click = (el) => {
      if (!el || !visible(el)) return false;
      el.scrollIntoView({ block: "center", inline: "center" });
      const rect = el.getBoundingClientRect();
      const eventInit = { bubbles: true, cancelable: true, view: window, clientX: rect.left + rect.width / 2, clientY: rect.top + rect.height / 2 };
      try { if (typeof el.focus === "function") el.focus({ preventScroll: true }); } catch {}
      for (const type of ["pointerdown", "mousedown", "pointerup", "mouseup", "click"]) {
        try { el.dispatchEvent(new MouseEvent(type, eventInit)); } catch {}
      }
      try { if (typeof el.click === "function") el.click(); } catch {}
      return true;
    };
    const popupCandidates = () => [...document.querySelectorAll("ytcp-playlist-dialog,tp-yt-paper-dialog,ytcp-dialog,[role=dialog],tp-yt-paper-listbox,[role=listbox]")]
      .filter(visible)
      .map((el) => {
        const rect = el.getBoundingClientRect();
        const text = clean(el.innerText || el.textContent || "");
        return {
          el,
          text,
          area: rect.width * rect.height,
        };
      })
      .filter((item) => {
        if (!item.text) return false;
        const hasPlaylistSignals = item.text.includes(target) || /新建播放列表|播放列表|playlist/i.test(item.text);
        const hasSelectionSignals = /完成|done|新建播放列表|创建/.test(item.text);
        return hasPlaylistSignals && hasSelectionSignals && item.area > 20000 && item.area < 1200000;
      });
    let roots = popupCandidates()
      .sort((left, right) => {
        const score = (item) => {
          let value = 0;
          if (item.text.includes(target)) value += 800;
          if (/播放列表|playlist/.test(item.text)) value += 260;
          if (/完成|done|新建播放列表|创建/.test(item.text)) value += 180;
          if (item.area > 30000 && item.area < 900000) value += 120;
          return value;
        };
        return score(right) - score(left) || left.area - right.area;
      });
    let root = roots[0]?.el || null;
    if (!root) {
      return {
        clicked: false,
        reason: "playlist_popup_not_open",
        candidates: [],
        dialog_text: "",
      };
    }
    const checkboxState = (el) => {
      if (!el) return false;
      const ariaChecked = String(el.getAttribute("aria-checked") || "").toLowerCase();
      if (ariaChecked === "true") return true;
      if (typeof el.checked === "boolean") return Boolean(el.checked);
      const cls = clean(typeof el.className === "string" ? el.className : "");
      return /(checked|selected|active)/i.test(cls) && !/(unchecked|disabled)/i.test(cls);
    };
    const collectOptionTargets = (scanRoot) => [...scanRoot.querySelectorAll("tp-yt-paper-checkbox,[role=checkbox],ytcp-checkbox-lit,label,button,[role=button],div,span")]
      .filter(visible)
      .map((el) => {
        const row = el.closest("tp-yt-paper-checkbox,[role=checkbox],ytcp-checkbox-lit,label,ytcp-playlist-dialog-row,div") || el;
        const text = clean(row.innerText || row.textContent || el.innerText || el.textContent || el.getAttribute("aria-label") || el.getAttribute("title") || "");
        const rect = row.getBoundingClientRect();
        const clickable = row.closest("label,button,[role=button],[role=option],[role=checkbox],tp-yt-paper-checkbox,ytcp-checkbox-lit,div,span") || row || el;
        const checkboxLike = row.closest("tp-yt-paper-checkbox,[role=checkbox],ytcp-checkbox-lit,label") || el.closest("tp-yt-paper-checkbox,[role=checkbox],ytcp-checkbox-lit,label") || null;
        const className = clean(typeof row.className === "string" ? row.className : "");
        const tag = String(row.tagName || el.tagName || "").toLowerCase();
        return {
          el: row || el,
          text,
          clickable,
          checkboxLike,
          area: rect.width * rect.height,
          checked: checkboxState(el) || checkboxState(row) || checkboxState(checkboxLike) || checkboxState(clickable),
          className,
          tag,
        };
      })
      .filter((item) => item.text && (item.text === target || item.text.includes(target)))
      .sort((left, right) => {
        const score = (item) => {
          let value = 0;
          if (item.text === target) value += 1000;
          else if (item.text.startsWith(target)) value += 700;
          else if (item.text.includes(target)) value += 500;
          if (item.checked) value += 120;
          if (item.checkboxLike) value += 280;
          if (/checkbox|playlist/.test(item.className)) value += 180;
          if (item.tag === "label" || item.tag === "button") value += 120;
          if (item.area > 200 && item.area < 120000) value += 60;
          return value;
        };
        return score(right) - score(left) || left.area - right.area;
      });
    let optionTargets = [];
    let stableEmptySeen = 0;
    for (let attempt = 0; attempt < 10; attempt += 1) {
      roots = popupCandidates().sort((left, right) => {
        const score = (item) => {
          let value = 0;
          if (item.text.includes(target)) value += 800;
          if (/播放列表|playlist/.test(item.text)) value += 260;
          if (/完成|done|新建播放列表|创建/.test(item.text)) value += 180;
          if (item.area > 30000 && item.area < 900000) value += 120;
          return value;
        };
        return score(right) - score(left) || left.area - right.area;
      });
      root = roots[0]?.el || root;
      if (!root) break;
      optionTargets = collectOptionTargets(root);
      if (optionTargets.length > 0) break;
      const textNow = clean(root.innerText || root.textContent || "");
      if (/没有可用的播放列表|No playlists available/i.test(textNow)) stableEmptySeen += 1;
      await sleep(350);
    }
    const option = optionTargets[0] || null;
    if (!option) {
      return {
        clicked: false,
        reason: "playlist_option_missing",
        stable_empty_seen: stableEmptySeen,
        candidates: [...new Set(
          [...root.querySelectorAll("*")]
            .filter(visible)
            .map((el) => clean(el.innerText || el.textContent || el.getAttribute("aria-label") || el.getAttribute("title") || ""))
            .filter(Boolean)
        )].slice(0, 30),
        dialog_text: clean(root?.innerText || root?.textContent || "").slice(0, 400),
      };
    }
    const optionClicked = option.checked ? true : click(option.checkboxLike || option.clickable || option.el);
    const doneCandidates = [...root.querySelectorAll("button,[role=button],tp-yt-paper-button,ytcp-button,div,span")]
      .filter(visible)
      .map((el) => ({
        el,
        text: clean(el.innerText || el.textContent || el.getAttribute("aria-label") || el.getAttribute("title") || ""),
        area: el.getBoundingClientRect().width * el.getBoundingClientRect().height,
        context: clean(el.closest("[role=dialog],tp-yt-paper-dialog,ytcp-dialog,ytcp-uploads-dialog")?.innerText || root.innerText || ""),
      }))
      .filter((item) => /^(完成|Done|确定|保存)$/i.test(item.text) && item.text.length <= 8 && /播放列表|playlist/i.test(item.context))
      .sort((left, right) => {
        const exactLeft = /^(完成|Done)$/i.test(left.text);
        const exactRight = /^(完成|Done)$/i.test(right.text);
        if (exactLeft !== exactRight) return exactRight - exactLeft;
        return left.area - right.area;
      });
    const done = doneCandidates[0] || null;
    const doneClicked = done ? click(done.el) : false;
    return {
      clicked: optionClicked,
      option_text: option.text,
      already_selected: option.checked,
      done_clicked: doneClicked,
      done_text: done?.text || "",
    };
  })()`, 9000);
  actions.push({ kind: "youtube_collection_select", ...selection, expected: target });
  if (
    selection?.clicked !== true
    && selection?.reason === "playlist_option_missing"
    && Number(selection?.stable_empty_seen || 0) >= 3
    && (
      /创建播放列表|Create playlist/i.test(String(selection?.dialog_text || ""))
      || (Array.isArray(selection?.candidates) && selection.candidates.some((item) => /创建播放列表|Create playlist/i.test(String(item || ""))))
    )
  ) {
    actions.push({
      kind: "youtube_collection_create_skipped",
      skipped: true,
      expected: target,
      reason: "existing_playlist_required",
    });
  }
  await sleep(900);
  const readback = await evaluateWithClient(client, `(() => {
    const target = ${JSON.stringify(target)};
    const clean = (value) => String(value || "").replace(/\\s+/g, " ").trim();
    const visible = (el) => {
      if (!el || typeof el.getBoundingClientRect !== "function") return false;
      const rect = el.getBoundingClientRect();
      const style = getComputedStyle(el);
      return rect.width > 0 && rect.height > 0 && style.display !== "none" && style.visibility !== "hidden";
    };
    const text = clean(((document.scrollingElement || document.documentElement || document.body)?.innerText) || "");
    const popupStillOpen = [...document.querySelectorAll("ytcp-playlist-dialog,tp-yt-paper-dialog,ytcp-dialog,[role=dialog],tp-yt-paper-listbox,[role=listbox]")]
      .filter(visible)
      .some((el) => {
        const dialogText = clean(el.innerText || el.textContent || "");
        return /播放列表|playlist/i.test(dialogText)
          && (
            dialogText.includes(target)
            || /新建播放列表|完成|Done|Create playlist/i.test(dialogText)
          );
      });
    const playlistRows = [...document.querySelectorAll("ytcp-video-metadata-playlists, ytcp-form-input-container")]
      .filter(visible)
      .map((el) => {
        const rect = el.getBoundingClientRect();
        return { text: clean(el.innerText || el.textContent || ""), area: rect.width * rect.height };
      })
      .filter((item) => item.area > 1000 && /播放列表|playlist/i.test(item.text))
      .sort((left, right) => left.area - right.area);
    const rowText = playlistRows[0]?.text || "";
    const verified = Boolean(!popupStillOpen && (rowText.includes(target) || text.includes(target)));
    return {
      verified,
      popup_still_open: popupStillOpen,
      expected: target,
      row_text: rowText.slice(0, 360),
      relevant_lines: text.split(/[\\n\\r]+| {2,}/).map(clean).filter((line) => /播放列表|playlist|新建播放列表|完成|Done/.test(line)).slice(0, 40),
    };
  })()`, 6000).catch((error) => ({
    verified: false,
    expected: target,
    reason: "youtube_collection_readback_error",
    message: String(error?.message || error || ""),
  }));
  if (
    !readback?.verified
    && selection?.clicked
    && selection?.done_clicked
    && String(selection?.option_text || "").includes(target)
    && (readback?.popup_still_open === false || readback?.reason === "youtube_collection_readback_error")
  ) {
    readback.verified = true;
    readback.action_confirmed = true;
    readback.reason = readback?.reason === "youtube_collection_readback_error"
      ? "playlist_action_confirmed_after_light_readback_timeout"
      : "playlist_action_confirmed_and_dialog_closed";
  }
  actions.push({ kind: "youtube_collection_readback", ...readback });
  if (!readback?.verified) {
    actions.push({
      kind: "youtube_collection_blocked",
      blocked: true,
      expected: target,
      reason: readback?.popup_still_open ? "playlist_dialog_not_confirmed" : "playlist_readback_mismatch",
      readback,
    });
  }
  return actions;
}

